refsection.programlisting:
      
u=lowdisc_ldgen(9,1,"halton");
b=2;
for k=1:9
    d=number_tobary(k,b);
    dstr=strcat(string(d),",");
    mprintf("%d [%s] %f\n",k,dstr,u(k))
end

      
u=lowdisc_ldgen(9,2,"halton");
b=3;
for k=1:9
    d=number_tobary(k,b);
    dstr=strcat(string(d),",");
    mprintf("%d [%s] %f\n",k,dstr,u(k,2))
end

      
